"""Quick checker: pass a code string defining p, returns (ok, nbytes).
Usage: python3 workdir/agentC_check.py 'p=lambda g:...'
Checks 3 validate examples + 262 arc-gen + 2000 random gen samples.
"""
import sys, json, types, importlib.util, random
sys.path.insert(0, '.')
from gen import validate
import gen

def check(code):
    g = {}
    exec(code, g)
    p = g['p']
    # validate 3
    d = validate()
    for split in ('train', 'test'):
        for ex in d[split]:
            if p(ex['input']) != ex['output']:
                return False, 'validate fail'
    # arc-gen
    data = json.load(open('data.json'))
    for e in data['arc-gen']:
        if p(e['input']) != e['output']:
            return False, 'arc-gen fail'
    # random
    random.seed(3)
    for _ in range(2000):
        ex = gen.generate()
        if p(ex['input']) != ex['output']:
            return False, 'random fail'
    return True, len(code)

if __name__ == '__main__':
    code = sys.argv[1]
    ok, info = check(code)
    print('bytes', len(code), 'OK' if ok else 'FAIL', info)

