"""Batch tester + mini search for task004. Tests many candidate code strings
against validate + arc-gen + N random samples. Prints passing ones with length.
"""
import sys, json, random
sys.path.insert(0, '.')
from gen import validate
import gen

# Build test set ONCE
D = validate()
VAL = [(ex['input'], ex['output']) for s in ('train', 'test') for ex in D[s]]
ARC = [(e['input'], e['output']) for e in json.load(open('data.json'))['arc-gen']]
random.seed(3)
RND = []
for _ in range(2000):
    ex = gen.generate()
    RND.append((ex['input'], ex['output']))
FULL = VAL + ARC + RND


def test(code, sample=None):
    try:
        G = {}
        exec(code, G)
        p = G['p']
    except Exception as e:
        return False, 'exc:' + str(e)
    cases = FULL if sample is None else (VAL + ARC + RND[:sample])
    for inp, out in cases:
        try:
            if p(inp) != out:
                return False, 'mismatch'
        except Exception as e:
            return False, 'run:' + str(e)
    return True, 'OK'


CANDIDATES = [
    # baseline
    "p=lambda g:[[[y,x][u<any(b)]for x,y,u in zip([0]+a,a,[0]+b)]for a,b in zip(g,g[1:]+g)]",
    # form B (prepend 0, shifted window)
    "p=lambda g:[[0]+[[y,x][u<any(b)]for x,y,u in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]",
]

if __name__ == '__main__':
    for c in CANDIDATES:
        ok, info = test(c)
        print(('PASS' if ok else 'fail'), len(c), info if not ok else '', repr(c) if ok and len(c) < 86 else '')

